 83→/// Read a blob from the entire/checkpoints/v1 branch by path
 84→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
 85→    let branch_ref = repo
 86→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
 87→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
 88→
 89→    let commit = branch_ref
 90→        .get()
 91→        .peel_to_commit()
 92→        .map_err(|e| format!("Failed to peel: {}", e))?;
 93→
 94→    let tree = commit
 95→        .tree()
 96→        .map_err(|e| format!("Failed to get tree: {}", e))?;
 97→
 98→    let entry = tree
 99→        .get_path(std::path::Path::new(path))
100→        .map_err(|e| format!("Path not found: {}", e))?;

