 5→#[derive(Debug, Serialize, Deserialize, Clone, Default)]
 6→pub struct EntireSettings {
 7→    pub enabled: Option<bool>,
 8→    pub local_dev: Option<bool>,
 9→    pub log_level: Option<String>,
10→    pub telemetry: Option<bool>,
11→}
12→
13→/// Read .entire/settings.json from a repo
14→pub fn read_settings(repo_path: &str) -> Result<EntireSettings, String> {
15→    let settings_path = Path::new(repo_path).join(".entire/settings.json");
16→    if !settings_path.exists() {
17→        return Err("No .entire/settings.json found".to_string());
18→    }
19→
20→    let content =
21→        fs::read_to_string(&settings_path).map_err(|e| format!("Failed to read settings: {}", e))?;
22→
23→    serde_json::from_str(&content).map_err(|e| format!("Failed to parse settings: {}", e))
24→}
25→
26→/// Check if a repo has Entire enabled
27→pub fn is_entire_enabled(repo_path: &str) -> bool {
28→    let entire_dir = Path::new(repo_path).join(".entire");
29→    if !entire_dir.exists() {
30→        return false;
31→    }
32→    match read_settings(repo_path) {
33→        Ok(settings) => settings.enabled.unwrap_or(false),
34→        Err(_) => false,
35→    }
36→}
37→
38→/// Discover repos with Entire enabled by scanning common directories
39→pub fn discover_repos() -> Vec<String> {
40→    let mut repos = Vec::new();
41→    let home = dirs_next().unwrap_or_default();
42→
43→    // Scan common project directories
44→    let scan_dirs = vec![
45→        PathBuf::from(&home).join("Projects"),
46→        PathBuf::from(&home).join("code"),
47→        PathBuf::from(&home).join("src"),
48→        PathBuf::from(&home).join("dev"),
49→    ];
50→
51→    for dir in scan_dirs {
52→        if dir.exists() {
53→            if let Ok(entries) = fs::read_dir(&dir) {
54→                for entry in entries.flatten() {
55→                    let path = entry.path();
56→                    if path.is_dir() && is_entire_enabled(&path.to_string_lossy()) {
57→                        repos.push(path.to_string_lossy().to_string());
58→                    }
59→                }
60→            }
61→        }
62→    }
63→
64→    repos
65→}
66→
67→fn dirs_next() -> Option<String> {
68→    std::env::var("HOME").ok()
69→}
