232→#[tauri::command]
233→fn spawn_agent(
234→    repo_path: String,
235→    agent: String,
236→    app: tauri::AppHandle,
237→    state: State<'_, Mutex<AppState>>,
238→) -> Result<String, String> {
239→    let app_handle = app.clone();
240→    let state = state.lock().map_err(|_| "State lock error".to_string())?;
241→
242→    state.pty_manager.spawn(&agent, &repo_path, move |session_id, data| {
243→        let _ = app_handle.emit("pty-output", serde_json::json!({
244→            "sessionId": session_id,
245→            "data": data,
246→        }));
247→    })
248→}
