295→#[derive(serde::Serialize)]
296→struct FileDiff {
297→    path: String,
298→    status: String, // "added", "modified", "deleted"
299→    hunks: Vec<DiffHunk>,
300→}
301→
302→#[derive(serde::Serialize)]
303→struct DiffHunk {
304→    header: String,
305→    lines: Vec<DiffLine>,
306→}
307→
308→#[derive(serde::Serialize)]
309→struct DiffLine {
310→    kind: String, // "add", "delete", "context"
311→    content: String,
312→    old_lineno: Option<u32>,
313→    new_lineno: Option<u32>,
314→}
315→
316→/// Convert a git2::Diff into our FileDiff structs
317→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
318→    let mut files: Vec<FileDiff> = Vec::new();
319→
320→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
321→        let path = delta
322→            .new_file()
323→            .path()
324→            .or_else(|| delta.old_file().path())
325→            .map(|p| p.to_string_lossy().to_string())
326→            .unwrap_or_default();
327→
328→        let status = match delta.status() {
329→            git2::Delta::Added => "added",
330→            git2::Delta::Deleted => "deleted",
331→            _ => "modified",
332→        };
333→
334→        // Ensure we have a FileDiff entry for this path
335→        if files.last().map_or(true, |f| f.path != path) {
336→            files.push(FileDiff {
337→                path: path.clone(),
338→                status: status.to_string(),
339→                hunks: Vec::new(),
340→            });
341→        }
342→
343→        let file = files.last_mut().unwrap();
344→
345→        // New hunk
346→        if let Some(h) = hunk {
347→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
348→            if file.hunks.last().map_or(true, |last| last.header != header) {
349→                file.hunks.push(DiffHunk {
350→                    header,
351→                    lines: Vec::new(),
352→                });
353→            }
354→        }
355→
356→        // Diff line
357→        if let Some(current_hunk) = file.hunks.last_mut() {
358→            let kind = match line.origin() {
359→                '+' => "add",
360→                '-' => "delete",
361→                ' ' => "context",
362→                _ => return true,
363→            };
364→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
365→            current_hunk.lines.push(DiffLine {
366→                kind: kind.to_string(),
367→                content,
368→                old_lineno: line.old_lineno(),
369→                new_lineno: line.new_lineno(),
370→            });
371→        }
372→
373→        true
374→    })
375→    .map_err(|e| format!("Failed to print diff: {}", e))?;
376→
377→    Ok(files)
378→}
