  1→import { useState, useEffect } from "react";
  2→import {
  3→  GitBranch,
  4→  BookOpen,
  5→  Plus,
  6→  ChevronRight,
  7→  ChevronDown,
  8→  FolderGit2,
  9→  Loader2,
 10→  PanelLeftClose,
 11→  PanelLeftOpen,
 12→} from "lucide-react";
 13→import type { Tab } from "../../App";
 14→import type { BranchInfo, WorktreeInfo } from "../../lib/ipc";
 15→import { useReposQuery } from "../../hooks/use-tauri-query";
 16→
 17→interface SidebarProps {
 18→  activeTab: Tab;
 19→  onBranchSelect: (branch: BranchInfo, repoPath: string) => void;
 20→  onWorktreeSelect: (wt: WorktreeInfo, repoPath: string) => void;
 21→  onNewSession?: () => void;
 22→}
 23→
 24→export function Sidebar({
 25→  activeTab,
 26→  onBranchSelect,
 27→  onWorktreeSelect,
 28→  onNewSession,
 29→}: SidebarProps) {
 30→  const { data: realRepos, isLoading, error } = useReposQuery();
 31→
 32→  const repos = realRepos ?? [];
 33→
 34→  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
 35→  const [repoListCollapsed, setRepoListCollapsed] = useState(false);
 36→  const [collapsed, setCollapsed] = useState(false);
 37→
 38→  // Auto-expand all repos when data loads
 39→  useEffect(() => {
 40→    setExpandedRepos(new Set(repos.map((r) => r.path)));
 41→  }, [repos]);
 42→
 43→  function toggleRepo(path: string) {
 44→    setExpandedRepos((prev) => {
 45→      const next = new Set(prev);
 46→      if (next.has(path)) next.delete(path);
 47→      else next.add(path);
 48→      return next;
 49→    });
 50→  }
 51→
 52→  const worktreeBranches = new Set(
 53→    repos.flatMap((r) => r.worktrees.map((wt) => wt.branch))
 54→  );
 55→
 56→  // Collapsed state: narrow icon rail
 57→  if (collapsed) {
 58→    return (
 59→      <div className="flex w-[48px] shrink-0 flex-col items-center border-r border-border bg-bg-raised py-3">
 60→        <button
 61→          onClick={() => setCollapsed(false)}
 62→          className="mb-4 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
 63→          title="Expand sidebar"
 64→        >
 65→          <PanelLeftOpen size={16} />
 66→        </button>
 67→        {repos.map((repo) => (
 68→          <button
 69→            key={repo.path}
 70→            className="mb-1 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
 71→            title={repo.name}
 72→          >
 73→            <BookOpen size={14} />
 74→          </button>
 75→        ))}
 76→        <div className="mt-auto">
 77→          <button
 78→            onClick={onNewSession}
 79→            className="flex h-8 w-8 items-center justify-center rounded text-accent-fg transition-colors hover:bg-accent-bg"
 80→            title="New Session"
 81→          >
 82→            <Plus size={16} />
 83→          </button>
 84→        </div>
 85→      </div>
 86→    );
 87→  }
 88→
 89→  return (
 90→    <div className="flex w-[240px] shrink-0 flex-col border-r border-border bg-bg-raised">
 91→      {/* Header */}
 92→      <div className="flex items-center border-b border-border-subtle p-4">
 93→        <h2 className="flex flex-1 items-center gap-2 text-[15px] font-semibold text-fg">
 94→          <FolderGit2 size={18} />
 95→          Repositories
 96→        </h2>
 97→        <button
 98→          onClick={() => setCollapsed(true)}
 99→          className="flex h-6 w-6 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
100→          title="Collapse sidebar"
101→        >
102→          <PanelLeftClose size={14} />
103→        </button>
104→      </div>
105→
106→      {/* Repo list */}
107→      <div className="flex-1 overflow-y-auto py-3">
108→        <button
109→          onClick={() => setRepoListCollapsed(!repoListCollapsed)}
110→          className="mb-1 flex w-full items-center gap-2 px-4 text-left"
111→        >
112→          {repoListCollapsed ? (
113→            <ChevronRight size={10} className="text-fg-subtle" />
114→          ) : (
115→            <ChevronDown size={10} className="text-fg-subtle" />
116→          )}
117→          <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
118→            Active
119→          </span>
120→          {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
121→        </button>
122→
123→        {error && !repoListCollapsed && (
124→          <div className="px-4 py-2 text-[11px] text-red">
125→            Failed to load repos
126→          </div>
127→        )}
128→
129→        {!repoListCollapsed && repos.map((repo) => (
130→          <div key={repo.path}>
131→            <button
132→              onClick={() => toggleRepo(repo.path)}
133→              className="flex w-full items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
134→            >
135→              {expandedRepos.has(repo.path) ? (
136→                <ChevronDown size={14} />
137→              ) : (
138→                <ChevronRight size={14} />
139→              )}
140→              <BookOpen size={14} />
141→              {repo.name}
142→              <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
143→                {repo.branches.length}
144→              </span>
145→            </button>
146→
147→            {expandedRepos.has(repo.path) && (
148→              <div className="pl-8">
149→                {repo.branches.map((branch) => {
150→                  const isWorktree = worktreeBranches.has(branch.name);
151→                  const isActive =
152→                    activeTab.branch === branch.name &&
153→                    activeTab.repoPath === repo.path;
154→
155→                  return (
156→                    <button
157→                      key={branch.name}
158→                      onClick={() => {
159→                        const wt = repo.worktrees.find(
160→                          (w) => w.branch === branch.name
161→                        );
162→                        if (wt) {
163→                          onWorktreeSelect(wt, repo.path);
164→                        } else {
165→                          onBranchSelect(branch, repo.path);
166→                        }
167→                      }}
168→                      className={`flex w-full items-center gap-2 px-2 py-[7px] text-[13px] transition-colors ${
169→                        isActive
170→                          ? "bg-accent-bg text-accent-fg"
171→                          : "text-fg-muted hover:bg-bg-hover hover:text-fg"
172→                      }`}
173→                    >
174→                      <GitBranch size={12} />
175→                      {branch.name}
176→                      {isWorktree && (
177→                        <span className="ml-auto rounded bg-green-bg px-1.5 py-0.5 text-[9px] font-medium text-green">
178→                          worktree
179→                        </span>
180→                      )}
181→                      {!isWorktree && (
182→                        <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
183→                          {branch.checkpoint_count}
184→                        </span>
185→                      )}
186→                    </button>
187→                  );
188→                })}
189→              </div>
190→            )}
191→          </div>
192→        ))}
193→
194→        {!repoListCollapsed && repos.length === 0 && !isLoading && !error && (
195→          <div className="px-4 py-6 text-center text-[11px] text-fg-subtle">
196→            No repositories discovered
197→          </div>
198→        )}
199→      </div>
200→
201→      {/* New session button */}
202→      <div className="border-t border-border-subtle p-3">
203→        <button
204→          onClick={onNewSession}
205→          className="flex w-full items-center justify-center gap-1.5 rounded-lg bg-accent px-3 py-2 text-xs font-medium text-white transition-colors hover:bg-accent-hover"
206→        >
207→          <Plus size={14} />
208→          New Session
209→        </button>
210→      </div>
211→    </div>
212→  );
213→}
