 1→import { useEffect, useRef } from "react";
 2→import { useQueryClient } from "@tanstack/react-query";
 3→import { invoke } from "@tauri-apps/api/core";
 4→import { useTauriEvent } from "./use-tauri-event";
 5→
 6→/**
 7→ * Watch a repo for file changes and auto-invalidate relevant queries.
 8→ * Starts the Rust file watcher for the repo on mount.
 9→ */
10→export function useLiveUpdates(repoPath: string) {
11→  const queryClient = useQueryClient();
12→  const startedRef = useRef<Set<string>>(new Set());
13→
14→  // Start watching on mount
15→  useEffect(() => {
16→    if (!repoPath || startedRef.current.has(repoPath)) return;
17→    startedRef.current.add(repoPath);
18→
19→    invoke("watch_repo", { repoPath }).catch((err) => {
20→      console.warn("Failed to start file watcher:", err);
21→    });
22→  }, [repoPath]);
23→
24→  // Invalidate checkpoint queries when checkpoints change
25→  useTauriEvent<{ repoPath: string }>("checkpoint-changed", (payload) => {
26→    if (payload.repoPath === repoPath || !repoPath) {
27→      queryClient.invalidateQueries({ queryKey: ["checkpoints"] });
28→    }
29→  });
30→
31→  // Invalidate session queries when sessions change
32→  useTauriEvent<{ repoPath: string }>("session-changed", (payload) => {
33→    if (payload.repoPath === repoPath || !repoPath) {
34→      queryClient.invalidateQueries({ queryKey: ["sessions"] });
35→      // Also refresh checkpoints since a session change may mean new checkpoint
36→      queryClient.invalidateQueries({ queryKey: ["checkpoints"] });
37→    }
38→  });
39→
40→  // Invalidate repo config queries when config changes
41→  useTauriEvent<{ repoPath: string }>("config-changed", (_payload) => {
42→    queryClient.invalidateQueries({ queryKey: ["repos"] });
43→  });
44→}
