380→#[tauri::command]
381→fn get_checkpoint_diff(
382→    repo_path: String,
383→    commit_sha: String,
384→) -> Result<Vec<FileDiff>, String> {
385→    if commit_sha.is_empty() {
386→        return Err("No commit SHA available for this checkpoint".to_string());
387→    }
388→
389→    let repo = git::open_repo(&repo_path)?;
390→    let oid = git2::Oid::from_str(&commit_sha)
391→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
392→    let commit = repo
393→        .find_commit(oid)
394→        .map_err(|e| format!("Commit not found: {}", e))?;
395→
396→    let tree = commit
397→        .tree()
398→        .map_err(|e| format!("Failed to get tree: {}", e))?;
399→
400→    // Diff against parent (or empty tree if no parent)
401→    let parent_tree = commit
402→        .parent(0)
403→        .ok()
404→        .and_then(|p| p.tree().ok());
405→
406→    let diff = repo
407→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
408→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
409→
410→    collect_diff_files(&diff)
411→}
412→
413→#[tauri::command]
414→fn get_branch_diff(
415→    repo_path: String,
416→    branch: String,
417→) -> Result<Vec<FileDiff>, String> {
418→    let repo = git::open_repo(&repo_path)?;
419→
420→    // Resolve the branch HEAD
421→    let branch_ref = repo
422→        .find_branch(&branch, git2::BranchType::Local)
423→        .map_err(|e| format!("Branch not found: {}", e))?;
424→    let branch_commit = branch_ref
425→        .get()
426→        .peel_to_commit()
427→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
428→
429→    // Find the default branch (try main, then master)
430→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
431→        "main"
432→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
433→        "master"
434→    } else {
435→        return Err("No default branch (main/master) found".to_string());
436→    };
437→
438→    // If we're diffing the default branch against itself, return empty
439→    if branch == default_branch_name {
440→        return Ok(Vec::new());
441→    }
442→
443→    let default_ref = repo
444→        .find_branch(default_branch_name, git2::BranchType::Local)
445→        .map_err(|e| format!("Default branch error: {}", e))?;
446→    let default_commit = default_ref
447→        .get()
448→        .peel_to_commit()
449→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
450→
451→    // Find merge base
452→    let merge_base_oid = repo
453→        .merge_base(default_commit.id(), branch_commit.id())
454→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
455→    let merge_base_commit = repo
456→        .find_commit(merge_base_oid)
457→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
458→
459→    let base_tree = merge_base_commit
460→        .tree()
461→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
462→    let branch_tree = branch_commit
463→        .tree()
464→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
465→
466→    let diff = repo
467→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
468→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
469→
470→    collect_diff_files(&diff)
471→}
