473→#[tauri::command]
474→fn watch_repo(
475→    repo_path: String,
476→    app: tauri::AppHandle,
477→    state: State<'_, Mutex<AppState>>,
478→) -> Result<(), String> {
479→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
480→
481→    // Don't double-watch
482→    if app_state.watched_repos.contains(&repo_path) {
483→        return Ok(());
484→    }
485→    app_state.watched_repos.insert(repo_path.clone());
486→
487→    let app_handle = app.clone();
488→    let repo_path_for_closure = repo_path.clone();
489→    watcher::watch_repo(&repo_path, move |event| {
490→        let event_name = match event {
491→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
492→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
493→            watcher::WatchEvent::ConfigChanged => "config-changed",
494→        };
495→        let _ = app_handle.emit(event_name, serde_json::json!({
496→            "repoPath": repo_path_for_closure,
497→        }));
498→    })?;
499→
500→    Ok(())
501→}
502→
503→#[cfg_attr(mobile, tauri::mobile_entry_point)]
504→pub fn run() {
505→    tauri::Builder::default()
506→        .plugin(tauri_plugin_opener::init())
507→        .plugin(tauri_plugin_window_state::Builder::default().build())
508→        .manage(Mutex::new(AppState {
509→            pty_manager: pty::PtyManager::new(),
510→            watched_repos: HashSet::new(),
511→        }))
512→        .manage(Mutex::new(ghostty::GhosttyState::new()))
513→        .setup(|app| {
514→            // System tray
515→            use tauri::menu::{MenuBuilder, MenuItemBuilder};
516→            use tauri::tray::TrayIconBuilder;
517→            use tauri::Manager;
518→
519→            let show = MenuItemBuilder::with_id("show", "Show Entire").build(app)?;
520→            let quit = MenuItemBuilder::with_id("quit", "Quit").build(app)?;
521→            let menu = MenuBuilder::new(app)
522→                .item(&show)
523→                .separator()
524→                .item(&quit)
525→                .build()?;
526→
527→            let _tray = TrayIconBuilder::new()
528→                .tooltip("Entire Desktop")
529→                .menu(&menu)
530→                .on_menu_event(move |app, event| {
531→                    match event.id().as_ref() {
532→                        "show" => {
533→                            if let Some(window) = app.get_webview_window("main") {
534→                                let _ = window.show();
535→                                let _ = window.set_focus();
536→                            }
537→                        }
538→                        "quit" => {
539→                            app.exit(0);
540→                        }
541→                        _ => {}
542→                    }
543→                })
544→                .on_tray_icon_event(|tray, event| {
545→                    if let tauri::tray::TrayIconEvent::Click { .. } = event {
546→                        let app = tray.app_handle();
547→                        if let Some(window) = app.get_webview_window("main") {
548→                            let _ = window.show();
549→                            let _ = window.set_focus();
550→                        }
551→                    }
552→                })
553→                .build(app)?;
554→
555→            Ok(())
556→        })
557→        .invoke_handler(tauri::generate_handler![
558→            list_repos,
559→            list_checkpoints,
560→            get_transcript,
561→            get_checkpoint_diff,
562→            get_branch_diff,
563→            list_sessions,
564→            get_entire_settings,
565→            get_entire_logs,
566→            get_checkpoint_logs,
567→            get_raw_checkpoint_metadata,
568→            get_raw_session_file,
569→            spawn_agent,
570→            pty_input,
571→            pty_resize,
572→            kill_pty,
573→            launch_ghostty_agent,
574→            list_trails,
575→            watch_repo,
576→            ghostty::commands::ghostty_create_surface,
577→            ghostty::commands::ghostty_destroy_surface,
578→            ghostty::commands::ghostty_update_overlay,
579→            ghostty::commands::ghostty_show_overlay,
580→            ghostty::commands::ghostty_focus_overlay,
581→            ghostty::commands::ghostty_send_text,
582→        ])
583→        .run(tauri::generate_context!())
584→        .expect("error while running tauri application");
585→}
