 24→export function Sidebar({
 25→  activeTab,
 26→  onBranchSelect,
 27→  onWorktreeSelect,
 28→  onNewSession,
 29→}: SidebarProps) {
 30→  const { data: realRepos, isLoading, error } = useReposQuery();
 31→
 32→  const repos = realRepos ?? [];
 33→
 34→  const [expandedRepos, setExpandedRepos] = useState<Set<string>>(new Set());
 35→  const [repoListCollapsed, setRepoListCollapsed] = useState(false);
 36→  const [collapsed, setCollapsed] = useState(false);
 37→
 38→  // Auto-expand all repos when data loads
 39→  useEffect(() => {
 40→    setExpandedRepos(new Set(repos.map((r) => r.path)));
 41→  }, [repos]);
 42→
 43→  function toggleRepo(path: string) {
 44→    setExpandedRepos((prev) => {
 45→      const next = new Set(prev);
 46→      if (next.has(path)) next.delete(path);
 47→      else next.add(path);
 48→      return next;
 49→    });
 50→  }
 51→
 52→  const worktreeBranches = new Set(
 53→    repos.flatMap((r) => r.worktrees.map((wt) => wt.branch))
 54→  );
 55→
 56→  // Collapsed state: narrow icon rail
 57→  if (collapsed) {
 58→    return (
 59→      <div className="flex w-[48px] shrink-0 flex-col items-center border-r border-border bg-bg-raised py-3">
 60→        <button
 61→          onClick={() => setCollapsed(false)}
 62→          className="mb-4 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
 63→          title="Expand sidebar"
 64→        >
 65→          <PanelLeftOpen size={16} />
 66→        </button>
 67→        {repos.map((repo) => (
 68→          <button
 69→            key={repo.path}
 70→            className="mb-1 flex h-8 w-8 items-center justify-center rounded text-fg-subtle transition-colors hover:bg-bg-hover hover:text-fg"
 71→            title={repo.name}
 72→          >
 73→            <BookOpen size={14} />
 74→          </button>
 75→        ))}
 76→        <div className="mt-auto">
 77→          <button
 78→            onClick={onNewSession}
 79→            className="flex h-8 w-8 items-center justify-center rounded text-accent-fg transition-colors hover:bg-accent-bg"
 80→            title="New Session"
 81→          >
 82→            <Plus size={16} />
 83→          </button>
 84→        </div>
 85→      </div>
 86→    );
 87→  }
 88→
 89→  return (
 90→    <div className="flex w-[240px] shrink-0 flex-col border-r border-border bg-bg-raised">
 91→      {/* Header */}
 92→      <div className="flex items-center border-b border-border-subtle p-4">
 93→        <h2 className="flex flex-1 items-center gap-2 text-[15px] font-semibold text-fg">
