100→          title="Collapse sidebar"
101→        >
102→          <PanelLeftClose size={14} />
103→        </button>
104→      </div>
105→
106→      {/* Repo list */}
107→      <div className="flex-1 overflow-y-auto py-3">
108→        <button
109→          onClick={() => setRepoListCollapsed(!repoListCollapsed)}
110→          className="mb-1 flex w-full items-center gap-2 px-4 text-left"
111→        >
112→          {repoListCollapsed ? (
113→            <ChevronRight size={10} className="text-fg-subtle" />
114→          ) : (
115→            <ChevronDown size={10} className="text-fg-subtle" />
116→          )}
117→          <span className="text-[10px] font-semibold uppercase tracking-wider text-fg-subtle">
118→            Active
119→          </span>
120→          {isLoading && <Loader2 size={10} className="animate-spin text-fg-subtle" />}
121→        </button>
122→
123→        {error && !repoListCollapsed && (
124→          <div className="px-4 py-2 text-[11px] text-red">
125→            Failed to load repos
126→          </div>
127→        )}
128→
129→        {!repoListCollapsed && repos.map((repo) => (
130→          <div key={repo.path}>
131→            <button
132→              onClick={() => toggleRepo(repo.path)}
133→              className="flex w-full items-center gap-2.5 px-4 py-[7px] text-[13px] text-fg-muted transition-colors hover:bg-bg-hover hover:text-fg"
134→            >
135→              {expandedRepos.has(repo.path) ? (
136→                <ChevronDown size={14} />
137→              ) : (
138→                <ChevronRight size={14} />
139→              )}
140→              <BookOpen size={14} />
141→              {repo.name}
142→              <span className="ml-auto rounded-lg bg-bg-hover px-1.5 text-[10px] text-fg-subtle">
143→                {repo.branches.length}
144→              </span>
145→            </button>
